// Validate and clean lead data
const lead = $json;

const errors = [];

// Validate required fields
if (!lead.name || lead.name.trim() === '') {
  errors.push('Name is required');
}

if (!lead.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email)) {
  errors.push('Valid email is required');
}

if (!lead.budget_min || !lead.budget_max) {
  errors.push('Budget range is required');
}

if (lead.budget_min > lead.budget_max) {
  errors.push('Minimum budget cannot be greater than maximum');
}

if (errors.length > 0) {
  throw new Error(`Validation failed: ${errors.join(', ')}`);
}

// Parse budget if string
const budget_min = typeof lead.budget_min === 'string' 
  ? parseInt(lead.budget_min.replace(/[^0-9]/g, '')) 
  : lead.budget_min;

const budget_max = typeof lead.budget_max === 'string' 
  ? parseInt(lead.budget_max.replace(/[^0-9]/g, '')) 
  : lead.budget_max;

return {
  name: lead.name.trim(),
  email: lead.email.toLowerCase().trim(),
  phone: lead.phone || null,
  budget_min,
  budget_max,
  location: lead.location || null,
  bedrooms: lead.bedrooms ? parseInt(lead.bedrooms) : null,
  bathrooms: lead.bathrooms ? parseFloat(lead.bathrooms) : null,
  must_haves: lead.must_haves || null,
  timeline: lead.timeline || 'Not specified',
  source: lead.source || 'website',
  contact_method: lead.contact_method || 'email',
  tenant_id: lead.tenant_id
};

