// Parse AI scoring response
try {
  const response = $json.body;
  const scoring = JSON.parse(response.text);

  return {
    ...scoring,
    priority: scoring.lead_score >= 80 ? 'HIGH' : scoring.lead_score >= 50 ? 'MEDIUM' : 'LOW'
  };
} catch (error) {
  console.error('Failed to parse scoring:', error);
  throw new Error(`Invalid AI response: ${error.message}`);
}

