// Parse and validate property rankings
try {
  const response = $json.body;
  const rankings = JSON.parse(response.text);

  if (!Array.isArray(rankings)) {
    throw new Error('Expected array of ranked properties');
  }

  return rankings.filter(r => r.match_score >= 50).sort((a, b) => b.match_score - a.match_score);
} catch (error) {
  console.error('Failed to parse rankings:', error);
  return [];
}

// Create CRM tasks based on lead score and priority
const leadId = $json[4][0][0].id;
const priority = $json[4][0][0].priority;
const leadScore = $json[4][0][0].lead_score;

const tasks = [];

// Immediate follow-up for high-priority leads
if (priority === 'HIGH') {
  tasks.push({
    title: `URGENT: Call lead (${leadScore}/100 score)`,
    description: 'High-priority lead with strong purchase likelihood. Call immediately.',
    action_type: 'call',
    priority: 'HIGH',
    due_date: new Date(Date.now() + 30 * 60 * 1000), // 30 minutes from now
    lead_id: leadId
  });
}

// Email with property suggestions
tasks.push({
  title: 'Send property matches via email',
  description: 'Send matched properties and virtual tour links',
  action_type: 'email',
  priority: priority === 'HIGH' ? 'HIGH' : 'MEDIUM',
  due_date: new Date(Date.now() + 60 * 60 * 1000), // 1 hour from now
  lead_id: leadId
});

// Schedule showings for top matches
if (priority === 'HIGH') {
  tasks.push({
    title: 'Schedule property showings',
    description: 'Arrange viewing appointments for top 3 matched properties',
    action_type: 'showing',
    priority: 'HIGH',
    due_date: new Date(Date.now() + 24 * 60 * 60 * 1000), // 24 hours
    lead_id: leadId
  });
}

// Follow-up for medium/low leads
if (priority !== 'HIGH') {
  tasks.push({
    title: 'Add to nurture campaign',
    description: 'Add to weekly email drip campaign with relevant properties',
    action_type: 'followup',
    priority: 'LOW',
    due_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7 days
    lead_id: leadId
  });
}

return tasks;

// Compile final response
const leadData = $json[5];
const rankings = $json[3];

return {
  success: true,
  lead: {
    id: leadData[0][0].id,
    name: $json[1].name,
    email: $json[1].email,
    lead_score: leadData[0][0].lead_score,
    priority: leadData[0][0].priority
  },
  matched_properties: rankings.slice(0, 5),
  next_actions: [
    leadData[0][0].priority === 'HIGH' ? '✓ IMMEDIATE: Call lead within 30 minutes' : '✓ Send email with properties',
    '✓ SEND: Property matches via email with virtual tours',
    leadData[0][0].priority === 'HIGH' ? '✓ SCHEDULE: Arrange showings for top 3 properties' : '✓ ADD: To nurture campaign',
    '✓ CRM_TASK: Created in agent dashboard'
  ],
  timestamp: new Date().toISOString()
};
